INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-c5fb3965-moex-00218', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '禮起於何也？曰：人生而有欲，欲而不得，則不能無求。求而無度量分界，則不能不爭；爭則亂，亂 則窮。先王惡其亂也，故制禮義以分之，以養人之欲，給人之求。使欲必不窮乎物，物必不屈於欲。 兩者相持而長，是禮之所起也。（《荀子・禮論》）下列敘述何者符合文意？', '["社會秩序混亂根本原因是資源不足", "作者認為人有天生自我節制的良知", "「禮」的功能類似經濟學中所謂供需可透過分配達到平衡", "「禮」的生成類似經濟學所說「看不見的手」所創造的市場規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00219', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '有五斗先生者，以酒德遊於人間，有以酒請者，無貴賤皆往，往必醉，醉則不擇地斯寢矣，醒則復起飲 也。常一飲五斗，因以為號焉。先生絶思慮，寡言語，不知天下之有仁義厚薄也。忽焉而去，倏然而來， 其動也天，其靜也地，故萬物不能縈心焉。嘗言曰：「天下大抵可見矣。生何足養，而嵇康著論；途何 為窮，而阮籍慟哭。故昏昏默默，聖人之所居也。」遂行其志，不知所如。（王績〈五斗先生傳〉） 下列選項，何者最適合用來形容五斗先生？', '["飯蔬飲水", "率性而為", "獨善其身", "縱情恣欲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00220', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '承上題，「故昏昏默默，聖人之所居也」，「昏昏」之意與下列何者最為相近？', '["「昏昏」欲睡", "俗人昭昭，我獨「昏昏」", "霏霏野霧合，「昏昏」隴日沉", "鸞絃代雁曲如語，一醉「昏昏」天下迷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00221', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '王戎喪兒萬子，山簡往省之，王悲不自勝，簡曰：「孩抱中物，何至於此？」王曰：「聖人忘情，最下 不及情；情之所鍾，正在我輩。」簡服其言，更為之慟。（《世說新語•傷逝》） 上文中的「我輩」具有何種特質？', '["以學聖人為人生目標", "具有社會地位與學識", "對所愛者有深刻感情", "會因年老而偏疼孩子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00222', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '再徙北城，所居止三席地，其左無壁，覆之以苫。日常使姊守舍，攜中及妹，傫然丐於親故，率日不 得一食；歸則藉藁於地。每冬夜號寒，母子相擁，不自意全濟，比見晨光，則欣然有生望焉。迨中入 學宮，游藝四方，稍致甘旨之養。母百病交攻，綿歷歲年，竟致不起。嗚呼痛哉！（汪中〈先母鄒孺 人靈表〉） 上文內容之書寫，未包括下列何者？', '["居住", "交通", "飲食", "臥寢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00223', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '承上題，汪中對於母親，其心情可用下列何者說明？', '["兒孫自有兒孫福", "養兒方知父母恩", "天下無不是父母", "子欲養而親不待"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00224', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '《格言聯璧》：「居處必先精勤，乃能閒暇。凡事務求停妥，然後逍遙。」 上文揭示的道理，與下列何者最為相近？', '["真積力久則入", "業精於勤，荒於嬉", "凡事豫則立，不豫則廢", "淡泊以明志，寧靜以致遠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00225', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '今斯地初開，雖風水屢洊而不為異，五患水，三患颱，而民不饑，無有散亂，何也？民皆手創其業， 艱難未忘，室家未阜，而不敢有淫慝之思也。雖然，吾特有懼焉，懼夫更十年後，地利盡闢，戶口殷 富，老者死而少者壯，民惟見其樂而不見其艱也，則將有滋為淫佚，而樂於兇悍暴亂者，人禍之興， 吾安知其所極耶？（姚瑩〈噶瑪蘭颱異記〉）根據上文，下列選項何者最貼近作者意旨？', '["移民墾荒剽悍勤奮，無畏天災人禍", "地盡其利，才能使民安居致富，得享豐足生活", "提醒移民務必抱持人定勝天的觀念，才能安居樂業", "警示後人不可因漸趨安樂而迷失本性，否則必將帶來災害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00226', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「親愛的孩子：來信收到了，你說，你越讀得多，越聽得多，越糊塗了：這是智慧之門將要開的信號， 千萬不要灰心。諺語說：『公說公有理，婆說婆有理』，世間這樣的公婆實在太多了。因為他（她）們 的立場不同，考察事物的角度不同，偏見是免不了的。……我們在日常生活中，到處都會碰到這類的 情形，要是聽公說了就信了，聽婆說了又信了，自己一點不懷疑，不想去追尋公婆的矛盾所在，不想 徹底去追求真假與是非，馬馬虎虎被牽著鼻子走的話，那才是真正的糊塗蟲。」 根據上文，下列選項何者與作者主張最為相近？', '["一切唯心造", "真理不辯自明", "盡信書不如無書", "偏見是無知的產物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00227', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '承上題，作者將「越讀得多，越聽得多，越糊塗了」視為智慧之門將要開的信號，其意在於表達：', '["福禍相倚，善惡互見", "困頓蟄伏，破繭重生", "見多識廣，心智澄明", "格物窮理，審問慎思"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
